parameters.jsonBody:
={{ JSON.stringify({
  data: [{
    Invoice_Number: $('Has Email?').item.json.invoiceNumber,
    Invoice_Date: $('Has Email?').item.json.invoiceDate.split('T')[0],
    Amount: $('Has Email?').item.json.items[0].total,
    Currency: $('Has Email?').item.json.currency,
    Name: $('Has Email?').item.json.invoiceNumber + ' - ' + $('Has Email?').item.json.billedTo.name,
    Item_Description: $('Has Email?').item.json.items.map(i => i.name).join(', '),
    Status: $('Has Email?').item.json.status,
    Bill_Type: $('Has Email?').item.json.billType,
    Invoice_URL: 'https://www.refrens.com/app/invoices/' + $('Has Email?').item.json._id,
    Contact: { id: $json.data[0].id }
  }]
}) }}

parameters.jsonOutput:
={{ {
  'Invoice Number': $('Split Invoices').item.json.invoiceNumber,
